class FinancialService(ServiceBase):
    @rpc(Unicode, _returns=BalanceResponse, _in_variable_names={'account_number': 'accountNumber'})
    def getBalance(ctx, account_number):
        """Get account balance for a given account number"""
        if account_number not in accounts_db:
            balance_response = BalanceResponse()
            balance_response.account_number = account_number
            balance_response.balance = Decimal("0.00")
            balance_response.currency = "USD"
            balance_response.available_balance = Decimal("0.00")
            return balance_response
        
        account = accounts_db[account_number]
        balance_response = BalanceResponse()
        balance_response.account_number = account_number
        balance_response.balance = Decimal(str(account["balance"]))
        balance_response.currency = account["currency"]
        balance_response.available_balance = Decimal(str(account["balance"] * 0.95))
        
        return balance_response

    @rpc(Unicode, Unicode, Decimal, Unicode, 
         _returns=TransferResponse,
         _in_variable_names={
             'from_account': 'fromAccount',
             'to_account': 'toAccount',
             'amount': 'amount',
             'description': 'description'
         })
    def transferFunds(ctx, from_account, to_account, amount, description):
        """Transfer funds between accounts"""
        transfer_response = TransferResponse()
        transfer_response.transaction_id = str(uuid.uuid4())
        transfer_response.from_account = from_account
        transfer_response.to_account = to_account
        transfer_response.amount = amount
        transfer_response.timestamp = datetime.now().isoformat()
        
        if from_account not in accounts_db:
            transfer_response.status = "FAILED"
            transfer_response.message = f"Source account {from_account} not found"
            return transfer_response
        
        if to_account not in accounts_db:
            transfer_response.status = "FAILED"
            transfer_response.message = f"Destination account {to_account} not found"
            return transfer_response
        
        if accounts_db[from_account]["status"] != "Active":
            transfer_response.status = "FAILED"
            transfer_response.message = f"Source account {from_account} is not active"
            return transfer_response
        
        if accounts_db[to_account]["status"] != "Active":
            transfer_response.status = "FAILED"
            transfer_response.message = f"Destination account {to_account} is not active"
            return transfer_response
        
        if accounts_db[from_account]["balance"] < float(amount):
            transfer_response.status = "FAILED"
            transfer_response.message = "Insufficient funds"
            return transfer_response
        
        if float(amount) <= 0:
            transfer_response.status = "FAILED"
            transfer_response.message = "Invalid amount"
            return transfer_response
        
        accounts_db[from_account]["balance"] -= float(amount)
        accounts_db[to_account]["balance"] += float(amount)
        
        transfer_response.status = "SUCCESS"
        transfer_response.message = f"Transfer of {amount} {accounts_db[from_account]['currency']} successful. {description}"
        
        return transfer_response

    @rpc(Unicode, _returns=AccountInfo, _in_variable_names={'account_number': 'accountNumber'})
    def getAccountInfo(ctx, account_number):
        """Get detailed account information"""
        account_info = AccountInfo()
        account_info.account_number = account_number
        
        if account_number not in accounts_db:
            account_info.account_holder = "Unknown"
            account_info.account_type = "Unknown"
            account_info.balance = Decimal("0.00")
            account_info.currency = "USD"
            account_info.created_date = ""
            account_info.status = "Not Found"
            return account_info
        
        account = accounts_db[account_number]
        account_info.account_holder = account["account_holder"]
        account_info.account_type = account["account_type"]
        account_info.balance = Decimal(str(account["balance"]))
        account_info.currency = account["currency"]
        account_info.created_date = account["created_date"]
        account_info.status = account["status"]
        
        return account_info


